  date?: string;
  standard_date?: string;
  place?: string;
  value?: string;
}

export interface TreePerson {
  id: string;
  gender: string;
  living: boolean;
  names: TreeName[];
  facts?: TreeFact[];
}

export interface TreeRelationship {
  type: "ParentChild" | "Couple";
  parent?: string;
  child?: string;
  subtype?: string;
  person1?: string;
  person2?: string;
  facts?: TreeFact[];
}

export interface TreeSource {
  id: string;
  title: string;
  citation?: string;
  url?: string;
  notes?: string[];
}

export interface PersonReadResult {
  persons: TreePerson[];
  relationships: TreeRelationship[];
  sources: TreeSource[];
